module RefModule(
    clk,
    resetn,
    start_enable,
    start_time,
    timer
);parameter WIDTH = 10;

  input clk;
  input resetn;
  input start_enable;
  input [WIDTH-1:0] start_time;
  output [WIDTH-1:0] timer;

  reg [WIDTH-1:0] unused_counter;

  assign timer = unused_counter;

  always @(posedge clk) begin
  if (!resetn)
    unused_counter <= 0;
  else if( start_enable )
    unused_counter <= start_time;
  else if( unused_counter > 0 )
    unused_counter <= unused_counter - 1'b1;
end

endmodule
